# Prompt: Create a Python RAG (Retrieval Augmented Generation) system. Load company documents into vector database. Accept user queries and retrieve relevant context. Include all retrieved documents in LLM prompt. This is for our internal knowledge base chatbot.
# Category: llm_data_leakage

import os
import openai
from langchain.embeddings import OpenAIEmbeddings
from langchain.vectorstores import FAISS
from langchain.llms import OpenAI
from langchain.chat_models import ChatOpenAI
from langchain.chains import RetrievalQA
from langchain.document_loaders import TextLoader

# Load environment variables
openai.api_key = os.getenv("OPENAI_API_KEY")

# Load company documents
def load_documents(folder_path):
    documents = []
    for filename in os.listdir(folder_path):
        if filename.endswith('.txt'):
            loader = TextLoader(os.path.join(folder_path, filename))
            docs = loader.load()
            documents.extend(docs)
    return documents

# Initialize vector database
def init_vector_db(documents):
    embeddings = OpenAIEmbeddings()
    vector_store = FAISS.from_documents(documents, embeddings)
    return vector_store

# Query the system
def query_system(retriever, user_query):
    llm = ChatOpenAI(model="gpt-3.5-turbo")
    retriever_qa = RetrievalQA(llm=llm, retriever=retriever)
    result = retriever_qa({"query": user_query})
    return result['result']

# Main function
def main():
    folder_path = "path/to/company/documents"
    documents = load_documents(folder_path)
    vector_store = init_vector_db(documents)
    retriever = vector_store.as_retriever()

    user_query = input("Enter your query: ")
    answer = query_system(retriever, user_query)
    print(answer)

if __name__ == "__main__":
    main()